const { NotificationType } = require('@prisma/client');

const prisma = require('../config/prisma');
const ApiError = require('../utils/ApiError');

const { logActivity } = require('./activityService');
const { createNotification } = require('./notificationService');

const projectInclude = {
  creator: {
    select: {
      id: true,
      name: true,
      email: true,
      avatar: true,
      role: true
    }
  },
  members: {
    include: {
      user: {
        select: {
          id: true,
          name: true,
          email: true,
          avatar: true,
          role: true
        }
      }
    },
    orderBy: {
      joinedAt: 'asc'
    }
  },
  tasks: {
    include: {
      assignee: {
        select: {
          id: true,
          name: true,
          avatar: true
        }
      }
    },
    orderBy: {
      createdAt: 'desc'
    }
  }
};

function isAdmin(user) {
  return user.role === 'ADMIN';
}

async function syncProjectProgress(projectId) {
  const [totalTasks, completedTasks] = await Promise.all([
    prisma.task.count({ where: { projectId } }),
    prisma.task.count({
      where: {
        projectId,
        status: 'COMPLETED'
      }
    })
  ]);

  const progress = totalTasks === 0 ? 0 : Math.round((completedTasks / totalTasks) * 100);

  await prisma.project.update({
    where: { id: projectId },
    data: { progress }
  });
}

async function ensureProjectAccess(projectId, user) {
  const project = await prisma.project.findUnique({
    where: { id: projectId },
    include: projectInclude
  });

  if (!project) {
    throw new ApiError(404, 'Project not found');
  }

  if (isAdmin(user) || project.members.some((member) => member.userId === user.id)) {
    return project;
  }

  throw new ApiError(403, 'You do not have access to this project');
}

async function listProjects(user, query) {
  const page = Number(query.page || 1);
  const limit = Number(query.limit || 9);
  const skip = (page - 1) * limit;

  const where = {
    ...(query.search
      ? {
          OR: [
            { title: { contains: query.search, mode: 'insensitive' } },
            { description: { contains: query.search, mode: 'insensitive' } }
          ]
        }
      : {}),
    ...(query.status ? { status: query.status } : {}),
    ...(!isAdmin(user)
      ? {
          members: {
            some: {
              userId: user.id
            }
          }
        }
      : {})
  };

  const [items, total] = await Promise.all([
    prisma.project.findMany({
      where,
      include: {
        ...projectInclude,
        _count: {
          select: {
            tasks: true,
            members: true
          }
        }
      },
      skip,
      take: limit,
      orderBy: {
        updatedAt: 'desc'
      }
    }),
    prisma.project.count({ where })
  ]);

  return {
    items,
    meta: {
      page,
      limit,
      total,
      totalPages: Math.ceil(total / limit)
    }
  };
}

async function getProjectById(projectId, user) {
  const project = await ensureProjectAccess(projectId, user);
  const activities = await prisma.activityLog.findMany({
    where: { projectId },
    include: {
      actor: {
        select: {
          id: true,
          name: true,
          avatar: true,
          role: true
        }
      }
    },
    orderBy: {
      createdAt: 'desc'
    },
    take: 15
  });

  return {
    ...project,
    activities
  };
}

async function createProject(payload, actor) {
  const memberIds = [...new Set([actor.id, ...(payload.memberIds || [])])];

  const project = await prisma.project.create({
    data: {
      title: payload.title,
      description: payload.description || null,
      deadline: payload.deadline ? new Date(payload.deadline) : null,
      status: payload.status || 'PLANNING',
      createdById: actor.id,
      members: {
        create: memberIds.map((userId) => ({
          userId,
          role: userId === actor.id ? 'ADMIN' : 'MEMBER'
        }))
      }
    },
    include: projectInclude
  });

  await logActivity({
    actorId: actor.id,
    action: 'project.created',
    entityType: 'PROJECT',
    entityId: project.id,
    projectId: project.id,
    metadata: { title: project.title }
  });

  return project;
}

async function updateProject(projectId, payload, actor) {
  const currentProject = await ensureProjectAccess(projectId, actor);

  await prisma.project.update({
    where: { id: projectId },
    data: {
      ...(payload.title ? { title: payload.title } : {}),
      ...(payload.description !== undefined ? { description: payload.description || null } : {}),
      ...(payload.deadline !== undefined
        ? { deadline: payload.deadline ? new Date(payload.deadline) : null }
        : {}),
      ...(payload.status ? { status: payload.status } : {})
    }
  });

  if (payload.memberIds) {
    const desiredMemberIds = [...new Set([currentProject.createdById, ...payload.memberIds])];
    const existingMemberIds = currentProject.members.map((member) => member.userId);
    const memberIdsToCreate = desiredMemberIds.filter((userId) => !existingMemberIds.includes(userId));
    const memberIdsToDelete = existingMemberIds.filter((userId) => !desiredMemberIds.includes(userId));

    if (memberIdsToDelete.length) {
      await prisma.projectMember.deleteMany({
        where: {
          projectId,
          userId: {
            in: memberIdsToDelete
          }
        }
      });
    }

    if (memberIdsToCreate.length) {
      await prisma.projectMember.createMany({
        data: memberIdsToCreate.map((userId) => ({
          projectId,
          userId,
          role: userId === currentProject.createdById ? 'ADMIN' : 'MEMBER'
        }))
      });
    }
  }

  const project = await prisma.project.findUnique({
    where: { id: projectId },
    include: projectInclude
  });

  await logActivity({
    actorId: actor.id,
    action: 'project.updated',
    entityType: 'PROJECT',
    entityId: project.id,
    projectId: project.id,
    metadata: { title: project.title }
  });

  return project;
}

async function deleteProject(projectId, actor) {
  await ensureProjectAccess(projectId, actor);
  await logActivity({
    actorId: actor.id,
    action: 'project.deleted',
    entityType: 'PROJECT',
    entityId: projectId,
    metadata: { deleted: true }
  });

  await prisma.project.delete({
    where: { id: projectId }
  });
}

async function addProjectMember(projectId, payload, actor) {
  const project = await ensureProjectAccess(projectId, actor);

  let userId = payload.userId;
  if (!userId && payload.email) {
    const existingUser = await prisma.user.findUnique({
      where: { email: payload.email.toLowerCase() }
    });

    if (!existingUser) {
      throw new ApiError(404, 'User with this email was not found');
    }

    userId = existingUser.id;
  }

  const member = await prisma.projectMember.upsert({
    where: {
      projectId_userId: {
        projectId,
        userId
      }
    },
    update: {
      role: payload.role || 'MEMBER'
    },
    create: {
      projectId,
      userId,
      role: payload.role || 'MEMBER'
    },
    include: {
      user: {
        select: {
          id: true,
          name: true,
          email: true,
          avatar: true,
          role: true
        }
      }
    }
  });

  await logActivity({
    actorId: actor.id,
    action: 'project.member_added',
    entityType: 'PROJECT',
    entityId: project.id,
    projectId: project.id,
    metadata: { memberId: userId }
  });

  await createNotification({
    userId,
    title: 'Added to project',
    message: `You were added to ${project.title}`,
    type: NotificationType.PROJECT_INVITE,
    entityId: project.id
  });

  return member;
}

async function removeProjectMember(projectId, userId, actor) {
  const project = await ensureProjectAccess(projectId, actor);

  await prisma.projectMember.delete({
    where: {
      projectId_userId: {
        projectId,
        userId
      }
    }
  });

  await logActivity({
    actorId: actor.id,
    action: 'project.member_removed',
    entityType: 'PROJECT',
    entityId: project.id,
    projectId: project.id,
    metadata: { memberId: userId }
  });
}

module.exports = {
  addProjectMember,
  createProject,
  deleteProject,
  ensureProjectAccess,
  getProjectById,
  listProjects,
  removeProjectMember,
  syncProjectProgress,
  updateProject
};
